-- Starter content templates + provision function
-- Generated by scripts/generate-starter-content.mjs

-- Template tables
CREATE TABLE IF NOT EXISTS public.starter_materials (
  starter_key text PRIMARY KEY,
  title text NOT NULL,
  content jsonb,
  level public.jlpt_level NOT NULL DEFAULT 'n5',
  category public.material_category NOT NULL,
  tags text[],
  vocabulary jsonb,
  grammar_notes jsonb,
  cultural_note text,
  indonesian_translation text,
  path public.learning_path NOT NULL DEFAULT 'jlpt_academic'
);

CREATE TABLE IF NOT EXISTS public.starter_vocab (
  starter_key text PRIMARY KEY,
  kanji text,
  kana text NOT NULL,
  meaning text NOT NULL,
  jlpt_level public.jlpt_level DEFAULT 'n5',
  tags text[]
);

ALTER TABLE public.starter_materials ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.starter_vocab ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Authenticated read starter materials"
  ON public.starter_materials FOR SELECT TO authenticated USING (true);
CREATE POLICY "Authenticated read starter vocab"
  ON public.starter_vocab FOR SELECT TO authenticated USING (true);

-- Columns for user content linking
ALTER TABLE public.materials
  ADD COLUMN IF NOT EXISTS starter_key text;

ALTER TABLE public.learning_lessons
  ADD COLUMN IF NOT EXISTS starter_key text;

CREATE INDEX IF NOT EXISTS idx_materials_user_starter_key
  ON public.materials (user_id, starter_key)
  WHERE starter_key IS NOT NULL;

-- Seed templates (idempotent)
ON CONFLICT (starter_key) DO UPDATE SET
  title = EXCLUDED.title,
  content = EXCLUDED.content,
  level = EXCLUDED.level,
  category = EXCLUDED.category,
  tags = EXCLUDED.tags,
  vocabulary = EXCLUDED.vocabulary,
  grammar_notes = EXCLUDED.grammar_notes,
  cultural_note = EXCLUDED.cultural_note,
  indonesian_translation = EXCLUDED.indonesian_translation,
  path = EXCLUDED.path;

ON CONFLICT (starter_key) DO UPDATE SET
  kanji = EXCLUDED.kanji,
  kana = EXCLUDED.kana,
  meaning = EXCLUDED.meaning,
  jlpt_level = EXCLUDED.jlpt_level,
  tags = EXCLUDED.tags;

-- Provision function
CREATE OR REPLACE FUNCTION public.provision_starter_content(p_user_id uuid, p_path public.learning_path DEFAULT 'jlpt_academic')
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_mat record;
  v_vocab record;
  v_new_mat_id uuid;
  v_new_vocab_id uuid;
BEGIN
  IF EXISTS (SELECT 1 FROM public.materials WHERE user_id = p_user_id LIMIT 1) THEN
    RETURN;
  END IF;

  FOR v_mat IN
    SELECT * FROM public.starter_materials
    ORDER BY starter_key
  LOOP
      user_id, title, content, level, category, tags,
      vocabulary, grammar_notes, cultural_note, indonesian_translation, starter_key
    ) VALUES (
      p_user_id, v_mat.title, v_mat.content, v_mat.level, v_mat.category, v_mat.tags,
      v_mat.vocabulary, v_mat.grammar_notes, v_mat.cultural_note, v_mat.indonesian_translation, v_mat.starter_key
    )
    RETURNING id INTO v_new_mat_id;
  END LOOP;

  FOR v_vocab IN
    SELECT * FROM public.starter_vocab
    ORDER BY starter_key
  LOOP
    VALUES (p_user_id, v_vocab.kanji, v_vocab.kana, v_vocab.meaning, v_vocab.jlpt_level, v_vocab.tags)
    RETURNING id INTO v_new_vocab_id;

    VALUES (p_user_id, v_new_vocab_id, 'new', 0, 2.5, 0, now());
  END LOOP;
END;
$$;

-- Update signup trigger
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER AS $$
BEGIN
  VALUES (NEW.id, COALESCE(NEW.raw_user_meta_data->>'display_name', NEW.email));
  PERFORM public.provision_starter_content(NEW.id, 'jlpt_academic');
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = public;

-- Backfill existing users without materials
DO $$
DECLARE
  r record;
BEGIN
  FOR r IN
    SELECT id, current_path FROM public.profiles p
    WHERE NOT EXISTS (SELECT 1 FROM public.materials m WHERE m.user_id = p.id)
  LOOP
    PERFORM public.provision_starter_content(r.id, r.current_path);
  END LOOP;
END $$;
